# Zero UUID used by Bambu printers for empty/unset tray_uuid
_ZERO_UUID = "00000000000000000000000000000000"


def _resolve_spool_tag(tray_info: dict) -> str:
    """Get the best spool identifier from tray info (prefer tray_uuid, fallback to filament_id)."""
    tray_uuid = tray_info.get("tray_uuid")
    if tray_uuid and tray_uuid != _ZERO_UUID:
        return tray_uuid
    filament_id = tray_info.get("filament_id")
    if filament_id:
        return filament_id
    return ""


def _parse_gcode_line(line: str) -> dict:
    """Parse a G-code line into a command and parameters."""
    parts = line.strip().split()
    if not parts:
        return {}
    cmd = parts[0]
    params = {}
    for part in parts[1:]:
        if len(part) < 2:
            continue
        key = part[0]
        try:
            value = float(part[1:])
        except ValueError:
            value = part[1:]
        params[key] = value
    return {"cmd": cmd, "params": params}


def _extract_filament_usage(gcode_lines: list) -> float:
    """Extract filament usage from G-code lines by summing E parameters."""
    total_e = 0.0
    last_e = None
    for line in gcode_lines:
        parsed = _parse_gcode_line(line)
        if not parsed:
            continue
        if parsed["cmd"].startswith("G") and "E" in parsed["params"]:
            e_val = parsed["params"]["E"]
            if last_e is not None:
                delta = e_val - last_e
                if delta > 0:
                    total_e += delta
            last_e = e_val
    return total_e


